mapper.select:
SELECT * FROM ( SELECT o.ORDER_ID, o.ORDER_NUMBER, o.USER_ID, u.EMAIL as USER_EMAIL, u.FIRST_NAME || ' ' || u.LAST_NAME as USER_NAME, o.ORDER_STATUS, o.TOTAL_AMOUNT, o.CURRENCY, o.PAYMENT_METHOD, o.ORDERED_AT, o.SHIPPED_AT, o.DELIVERED_AT, order_details.ITEM_COUNT, order_details.UNIQUE_PRODUCTS, order_details.AVG_ITEM_PRICE, order_details.DISCOUNT_PERCENTAGE, -- 주문 처리 시간 분석 CASE WHEN o.SHIPPED_AT IS NOT NULL THEN ROUND(EXTRACT(DAY FROM (o.SHIPPED_AT - o.ORDERED_AT)) * 24 + EXTRACT(HOUR FROM (o.SHIPPED_AT - o.ORDERED_AT)), 2) ELSE NULL END as HOURS_TO_SHIP, CASE WHEN o.DELIVERED_AT IS NOT NULL THEN ROUND(EXTRACT(DAY FROM (o.DELIVERED_AT - o.ORDERED_AT)) * 24 + EXTRACT(HOUR FROM (o.DELIVERED_AT - o.ORDERED_AT)), 2) ELSE NULL END as HOURS_TO_DELIVER, -- 고객 주문 패턴 분석 customer_stats.CUSTOMER_ORDER_COUNT, customer_stats.CUSTOMER_TOTAL_SPENT, customer_stats.CUSTOMER_AVG_ORDER_VALUE, DENSE_RANK() OVER (PARTITION BY u.USER_ID ORDER BY o.ORDERED_AT) as CUSTOMER_ORDER_SEQUENCE, -- 주문 가치 분석 CASE WHEN o.TOTAL_AMOUNT >= 500 THEN 'HIGH_VALUE' WHEN o.TOTAL_AMOUNT >= 100 THEN 'MEDIUM_VALUE' ELSE 'LOW_VALUE' END as ORDER_VALUE_CATEGORY, -- 계절성 분석 TO_CHAR(o.ORDERED_AT, 'Q') as ORDER_QUARTER, TO_CHAR(o.ORDERED_AT, 'MM') as ORDER_MONTH, TO_CHAR(o.ORDERED_AT, 'D') as ORDER_DAY_OF_WEEK, -- 지역 정보 NVL(shipping_addr.COUNTRY, 'UNKNOWN') as SHIPPING_COUNTRY, NVL(shipping_addr.STATE, 'UNKNOWN') as SHIPPING_STATE, -- 주문 복잡도 점수 (order_details.UNIQUE_PRODUCTS * 0.3 + order_details.ITEM_COUNT * 0.2 + CASE WHEN o.DISCOUNT_AMOUNT > 0 THEN 10 ELSE 0 END + CASE WHEN shipping_addr.COUNTRY != 'US' THEN 15 ELSE 0 END) as COMPLEXITY_SCORE, ROW_NUMBER() OVER (ORDER BY o.ORDERED_AT DESC) as RN FROM ORDERS o, USERS u, USER_ADDRESSES shipping_addr, (SELECT oi.ORDER_ID, COUNT(*) as ITEM_COUNT, COUNT(DISTINCT oi.PRODUCT_ID) as UNIQUE_PRODUCTS, ROUND(AVG(oi.UNIT_PRICE), 2) as AVG_ITEM_PRICE, ROUND(MAX(o2.DISCOUNT_AMOUNT) / NULLIF(MAX(o2.SUBTOTAL), 0) * 100, 2) as DISCOUNT_PERCENTAGE FROM ORDER_ITEMS oi, ORDERS o2 WHERE oi.ORDER_ID = o2.ORDER_ID GROUP BY oi.ORDER_ID) order_details, (SELECT o3.USER_ID, COUNT(*) as CUSTOMER_ORDER_COUNT, SUM(o3.TOTAL_AMOUNT) as CUSTOMER_TOTAL_SPENT, ROUND(AVG(o3.TOTAL_AMOUNT), 2) as CUSTOMER_AVG_ORDER_VALUE FROM ORDERS o3 WHERE o3.ORDER_STATUS NOT IN ('CANCELLED', 'REFUNDED') GROUP BY o3.USER_ID) customer_stats WHERE o.USER_ID = u.USER_ID AND o.SHIPPING_ADDRESS_ID = shipping_addr.ADDRESS_ID(+) AND o.ORDER_ID = order_details.ORDER_ID(+) AND o.USER_ID = customer_stats.USER_ID(+)
AND UPPER(o.ORDER_NUMBER) LIKE '%' || UPPER(#{orderNumber}) || '%'
AND UPPER(u.EMAIL) LIKE '%' || UPPER(#{userEmail}) || '%'
AND o.ORDER_STATUS = #{orderStatus}
AND o.PAYMENT_METHOD = #{paymentMethod}
AND CASE WHEN o.TOTAL_AMOUNT >= 500 THEN 'HIGH_VALUE' WHEN o.TOTAL_AMOUNT >= 100 THEN 'MEDIUM_VALUE' ELSE 'LOW_VALUE' END = #{orderValueCategory}
AND NVL(shipping_addr.COUNTRY, 'UNKNOWN') = #{shippingCountry}
AND o.ORDERED_AT >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND o.ORDERED_AT <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND o.TOTAL_AMOUNT >= #{minAmount}
AND o.TOTAL_AMOUNT <= #{maxAmount}
)
WHERE ROWNUM <= #{offset} + #{limit} AND RN > #{offset}
ORDER BY ORDERED_AT DESC

SELECT COUNT(*) as count
FROM ORDERS o,
     USERS u
WHERE o.USER_ID = u.USER_ID(+)
AND 1=1

        AND (
            UPPER(o.ORDER_NUMBER) LIKE UPPER('%' || #{searchKeyword} || '%')
            OR UPPER(u.EMAIL) LIKE UPPER('%' || #{searchKeyword} || '%')
            OR UPPER(u.FIRST_NAME || ' ' || u.LAST_NAME) LIKE UPPER('%' || #{searchKeyword} || '%')
        )


        AND o.ORDER_STATUS = #{statusFilter}


        AND o.PAYMENT_METHOD = #{paymentMethodFilter}


         AND o.TOTAL_AMOUNT >= #{minAmount} 


         AND o.TOTAL_AMOUNT <= #{maxAmount} 



        AND o.ORDERED_AT >= TO_DATE(#{startDate}, 'YYYY-MM-DD')




        AND o.ORDERED_AT <= TO_DATE(#{endDate}, 'YYYY-MM-DD') + 1

mapper.update:
UPDATE ORDERS
SET UPDATED_AT = SYSDATE
WHERE ORDER_ID = #{orderId}
